import { useCallback } from 'react';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Chip from '@mui/material/Chip';
import { PixiCanvas } from './render/PixiCanvas';
import { useViewport } from './engine/store/viewportStore';
import type { FractalRenderer } from './render/FractalRenderer';
import { generateScenario } from './services/mock/generator';
import { loadScenarioIntoStore } from './services/mock/loader';
import { useSimulationStore } from './engine/store/simulationStore';

/**
 * LOD labels for display.
 */
const LOD_LABELS = ['Heatmap', 'Bars', 'Capsules'] as const;
const LOD_COLORS = ['error', 'info', 'success'] as const;

/**
 * Root application component.
 * Integrates PixiJS canvas with React overlays.
 */
export default function App() {
  const lod = useViewport((s) => s.lod);
  const scale = useViewport((s) => s.scale);

  const handleRendererReady = useCallback((_renderer: FractalRenderer) => {
    const scenario = generateScenario('large');
    loadScenarioIntoStore(scenario, useSimulationStore.getState());
  }, []);

  const pxPerHour = (scale * 3600000).toFixed(2);

  return (
    <Box
      sx={{
        width: '100vw',
        height: '100vh',
        display: 'flex',
        flexDirection: 'column',
        bgcolor: 'background.default',
      }}
    >
      {/* Header */}
      <Box
        component="header"
        sx={{
          p: 1.5,
          borderBottom: 1,
          borderColor: 'divider',
          bgcolor: 'background.paper',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <Box>
          <Typography variant="h6" component="h1" sx={{ fontWeight: 600 }}>
            MMS Fractal Planner
          </Typography>
          <Typography variant="caption" color="text.secondary">
            128 trains × 12 years
          </Typography>
        </Box>
        <Box sx={{ display: 'flex', gap: 1, alignItems: 'center' }}>
          <Typography variant="caption" color="text.secondary">
            {pxPerHour} px/h
          </Typography>
          <Chip
            label={`LOD ${lod}: ${LOD_LABELS[lod]}`}
            color={LOD_COLORS[lod]}
            size="small"
            variant="outlined"
          />
        </Box>
      </Box>

      {/* Main canvas area */}
      <Box
        sx={{
          flex: 1,
          position: 'relative',
          overflow: 'hidden',
        }}
      >
        <PixiCanvas debug={false} onReady={handleRendererReady} />
      </Box>
    </Box>
  );
}

