     5→
     6→/**
     7→ * BarsLayer - LOD 1 renderer for medium zoom levels.
     8→ *
     9→ * Renders schedule blocks as colored bars with type-based stacking.
    10→ * Uses Graphics pooling for efficient batch rendering.
    11→ *
    12→ * Performance: Pre-allocates Graphics objects and reuses them,
    13→ * only drawing visible blocks (view frustum culling).
    14→ */
    15→
    16→export interface BarsConfig {
    17→  /** Row height in pixels */
    18→  rowHeight: number;
    19→  /** Number of train rows */
    20→  numRows: number;
    21→  /** Minimum bar width to render */
    22→  minBarWidth: number;
    23→  /** Bar height as fraction of row height */
    24→  barHeightRatio: number;
    25→}
    26→
    27→const DEFAULT_CONFIG: BarsConfig = {
    28→  rowHeight: 40,
    29→  numRows: 128,
    30→  minBarWidth: 2,
    31→  barHeightRatio: 0.8,
    32→};
    33→
    34→/** Colors for each maintenance type */
    35→const TYPE_COLORS: Record<BlockTypeValue, number> = {
    36→  [BlockType.PM]: 0x3ddc84,         // Green - Preventive
    37→  [BlockType.OVERHAUL]: 0xff6b35,   // Orange - Major
    38→  [BlockType.INSPECTION]: 0x4ecdc4, // Cyan - Inspection
    39→  [BlockType.REPAIR]: 0xd62828,     // Red - Repair
    40→  [BlockType.CLEANING]: 0x9b59b6,   // Purple - Cleaning
    41→};
    42→
    43→/** Pre-allocated arrays for batch transform */
    44→const MAX_VISIBLE_BLOCKS = 5000;
    45→const tempX = new Float32Array(MAX_VISIBLE_BLOCKS);
    46→const tempWidth = new Float32Array(MAX_VISIBLE_BLOCKS);
    47→
    48→export class BarsLayer {
    49→  private container: Container;
    50→  private barsGraphics: Graphics;
    51→  private config: BarsConfig;
    52→  private isDirty = true;
    53→
    54→  /** Visible block indices for current frame */
    55→  private visibleIndices: number[] = [];
    56→
    57→  constructor(config: Partial<BarsConfig> = {}) {
    58→    this.config = { ...DEFAULT_CONFIG, ...config };
    59→    this.container = new Container();
    60→    this.container.label = 'bars-layer';
    61→
    62→    // Single Graphics object for all bars (batched rendering)
    63→    this.barsGraphics = new Graphics();
    64→    this.barsGraphics.label = 'bars-graphics';
    65→    this.container.addChild(this.barsGraphics);
    66→  }
    67→
    68→  /**
    69→   * Get the container for adding to stage.
    70→   */
    71→  getContainer(): Container {
    72→    return this.container;
    73→  }
    74→
    75→  /**
    76→   * Mark layer as needing recalculation.
    77→   */
    78→  markDirty(): void {
    79→    this.isDirty = true;
    80→  }
    81→
    82→  /**
    83→   * Update and render the bars.
    84→   */
    85→  update(): void {
    86→    if (!this.isDirty) return;
    87→
    88→    this.cullVisibleBlocks();
    89→    this.renderBars();
    90→    this.isDirty = false;
    91→  }
    92→
    93→  /**
    94→   * Determine which blocks are visible in the current viewport.
    95→   * Uses view frustum culling for performance.
    96→   */
    97→  private cullVisibleBlocks(): void {
    98→    const { schedule } = getSimulationState();
    99→    const viewport = getViewportState();
   100→    const { numRows } = this.config;
   101→
   102→    this.visibleIndices = [];
   103→
   104→    if (schedule.count === 0) return;
   105→
   106→    // Calculate visible time range
   107→    const { originTime, scale, offsetX, width, height, offsetY } = viewport;
   108→    const viewStartTime = (0 - offsetX) / scale + originTime;
   109→    const viewEndTime = (width - offsetX) / scale + originTime;
   110→
   111→    // Calculate visible row range
   112→    const viewStartRow = Math.max(0, Math.floor(-offsetY / this.config.rowHeight));
   113→    const viewEndRow = Math.min(numRows, Math.ceil((height - offsetY) / this.config.rowHeight));
   114→
   115→    // Cull blocks
   116→    for (let i = 0; i < schedule.count && this.visibleIndices.length < MAX_VISIBLE_BLOCKS; i++) {
   117→      const blockStart = schedule.startTimes[i];
   118→      const blockEnd = schedule.endTimes[i];
   119→      const trainId = schedule.trainIds[i];
   120→
   121→      // Skip if outside visible time range
   122→      if (blockEnd < viewStartTime || blockStart > viewEndTime) continue;
   123→
   124→      // Skip if outside visible row range
   125→      if (trainId < viewStartRow || trainId > viewEndRow) continue;
   126→
   127→      this.visibleIndices.push(i);
   128→    }
   129→  }
   130→
   131→  /**
   132→   * Render visible bars using batched Graphics.
   133→   */
   134→  private renderBars(): void {
   135→    const { schedule } = getSimulationState();
   136→    const viewport = getViewportState();
   137→    const { rowHeight, minBarWidth, barHeightRatio } = this.config;
   138→
   139→    this.barsGraphics.clear();
   140→
   141→    if (this.visibleIndices.length === 0) return;
   142→
   143→    // Batch transform time to pixels
   144→    const count = this.visibleIndices.length;
   145→
   146→    // Create temporary arrays for visible blocks
   147→    const visibleStartTimes = new Float64Array(count);
   148→    const visibleEndTimes = new Float64Array(count);
   149→
   150→    for (let i = 0; i < count; i++) {
   151→      const idx = this.visibleIndices[i];
   152→      visibleStartTimes[i] = schedule.startTimes[idx];
   153→      visibleEndTimes[i] = schedule.endTimes[idx];
   154→    }
   155→
   156→    batchTimeToPixel(visibleStartTimes, visibleEndTimes, count, tempX, tempWidth);
   157→
   158→    // Calculate bar geometry
   159→    const barHeight = rowHeight * barHeightRatio;
   160→    const barYOffset = (rowHeight - barHeight) / 2;
   161→
   162→    // Draw bars by type for better batching
   163→    for (const typeValue of Object.values(BlockType)) {
   164→      if (typeof typeValue !== 'number') continue;
   165→
   166→      const color = TYPE_COLORS[typeValue as BlockTypeValue];
   167→
   168→      for (let i = 0; i < count; i++) {
   169→        const idx = this.visibleIndices[i];
   170→        const blockType = schedule.types[idx];
   171→
   172→        if (blockType !== typeValue) continue;
   173→
   174→        const x = tempX[i];
   175→        const width = Math.max(minBarWidth, tempWidth[i]);
   176→        const trainId = schedule.trainIds[idx];
   177→        const y = trainId * rowHeight + barYOffset + viewport.offsetY;
   178→
   179→        // Skip if completely outside viewport
   180→        if (x + width < 0 || x > viewport.width) continue;
   181→
   182→        // Get flags for visual state
   183→        const flags = schedule.flags[idx];
   184→        const isSelected = (flags & 1) !== 0;
   185→        const isDragging = (flags & 2) !== 0;
   186→        const hasConflict = (flags & 4) !== 0;
   187→
   188→        // Determine bar color based on state
   189→        let barColor = color;
   190→        let alpha = 0.9;
   191→
   192→        if (hasConflict) {
   193→          barColor = 0xff0000;
   194→          alpha = 0.8;
   195→        } else if (isDragging) {
   196→          alpha = 0.5;
   197→        }
   198→
   199→        // Draw rounded rectangle
   200→        this.barsGraphics.roundRect(x, y, width, barHeight, 3);
   201→        this.barsGraphics.fill({ color: barColor, alpha });
   202→
   203→        // Draw selection border
   204→        if (isSelected) {
   205→          this.barsGraphics.roundRect(x, y, width, barHeight, 3);
   206→          this.barsGraphics.stroke({ width: 2, color: 0xffffff });
   207→        }
   208→      }
   209→    }
   210→  }
   211→
   212→  /**
   213→   * Get block index at screen position, or -1 if none.
   214→   */
   215→  hitTest(screenX: number, screenY: number): number {
   216→    const { schedule } = getSimulationState();
   217→    const viewport = getViewportState();
   218→    const { rowHeight, barHeightRatio } = this.config;
   219→
   220→    const barHeight = rowHeight * barHeightRatio;
   221→    const barYOffset = (rowHeight - barHeight) / 2;
   222→
   223→    // Calculate which row was clicked
   224→    const row = Math.floor((screenY - viewport.offsetY) / rowHeight);
   225→
   226→    // Check visible blocks in that row
   227→    for (let i = 0; i < this.visibleIndices.length; i++) {
   228→      const idx = this.visibleIndices[i];
   229→
   230→      if (schedule.trainIds[idx] !== row) continue;
   231→
   232→      const x = tempX[i];
   233→      const width = tempWidth[i];
   234→      const y = row * rowHeight + barYOffset + viewport.offsetY;
   235→
   236→      // Check if click is within bar bounds
   237→      if (
   238→        screenX >= x &&
   239→        screenX <= x + width &&
   240→        screenY >= y &&
   241→        screenY <= y + barHeight
   242→      ) {
   243→        return idx;
   244→      }
   245→    }
   246→
   247→    return -1;
   248→  }
   249→
   250→  /**
   251→   * Resize the layer.
   252→   */
   253→  resize(_width: number, _height: number): void {
   254→    this.markDirty();
   255→  }
   256→
   257→  /**
