import { getSimulationState } from '../../engine/store/simulationStore';
import type { GeneratedScenario } from './generator';

/**
 * Load a generated scenario into the SoA simulation store.
 * Populates TypedArrays directly for high-performance access.
 */
export function loadScenarioIntoStore(scenario: GeneratedScenario): void {
  const store = getSimulationState();

  // Ensure capacity
  if (scenario.blocks.length > store.schedule.capacity) {
    store.initializeSchedule(Math.ceil(scenario.blocks.length * 1.5));
  }

  const schedule = store.schedule;

  // Populate TypedArrays
  for (let i = 0; i < scenario.blocks.length; i++) {
    const block = scenario.blocks[i];
    schedule.startTimes[i] = block.startTime;
    schedule.endTimes[i] = block.endTime;
    schedule.trainIds[i] = block.trainIndex;
    schedule.types[i] = block.type;
    schedule.trackIds[i] = block.trackId;
    schedule.flags[i] = 0;
  }

  schedule.count = scenario.blocks.length;

  store.trainLookup.clear();
  for (const train of scenario.trains) {
    store.trainLookup.set(train.index, {
      id: train.id,
      name: train.id,
      fleet: train.type,
    });
  }
}

